// ============================================================
// Level 0: 普通变量
// ============================================================
int x = 42;           // x 是一个整数，值为42

// 内存布局:
// ┌─────────┐
// │ x: 42   │  地址: 0x1000
// └─────────┘

// ============================================================
// Level 1: 一级指针 (指向变量的指针)
// ============================================================
int *p = &x;          // p 指向 x

// 内存布局:
// ┌─────────┐     ┌─────────┐
// │ p: 0x1000│────→│ x: 42   │
// │ 0x2000  │     │ 0x1000  │
// └─────────┘     └─────────┘

// 语义:
//   p     → 指针本身的值 (0x2000)
//   *p    → 解引用，得到指向的值 (42)
//   &p    → 指针自身的地址 (0x2000)

// ============================================================
// Level 2: 二级指针 (指向指针的指针)
// ============================================================
int **pp = &p;        // pp 指向 p

// 内存布局:
// ┌─────────┐     ┌─────────┐     ┌─────────┐
// │ pp:0x2000│────→│ p:0x1000│────→│ x: 42   │
// │ 0x3000  │     │ 0x2000  │     │ 0x1000  │
// └─────────┘     └─────────┘     └─────────┘

// 语义:
//   pp    → 二级指针本身的值 (0x3000)
//   *pp   → 解引用一次，得到p的值 (0x1000，即x的地址)
//   **pp  → 解引用两次，得到x的值 (42)
//   &pp   → 二级指针自身的地址 (0x3000)

// ============================================================
// Level 3: 三级指针 (指向二级指针的指针)
// ============================================================
int ***ppp = &pp;     // ppp 指向 pp

// 语义:
//   ppp    → 0x4000 (ppp自身的值)
//   *ppp   → 0x3000 (pp的值)
//   **ppp  → 0x1000 (x的地址，通过pp→p)
//   ***ppp → 42     (x的值，通过pp→p→x)
